head.script:
scwin.onpageload = function () {};

// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    console.log("----------- onUdcCompleted");
    $c.gus.cfDisableBtn([b_Update, b_Cancel, b_Save, b_Apprv, b_CancelApprv, btn_fileNm, btn_userId]); // 
    $c.gus.cfDisableObjects(
        [
            ed_userId,
            txt_userNm,
            txt_vehclNo,
            txt_vehclNm,
            lc_fuelKndCd,
            txt_carVolume,
            lc_apprvYn,
            lc_useYn,
            // txt_fileNm,
            txt_flEffcncy]
    );
    s_lc_useYn.setSelectedIndex(1);

    // gr_vehclInfo.setColumnVisible("acctDeptNm", true);
};

//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function (varGrNm) {
    var totCnt = ds_vehclInfo.getTotalRow();
    if (totCnt != 0) {
        let messageStr = "EXCEL로 다운로드 받으시겠습니까?";
        let downloadVal = await $c.win.confirm(messageStr);

        let sheetTitle = "차량정보";
        if (downloadVal) {
            const grdObj = gr_vehclInfo;
            const infoArr = [];
            const options = {
                fileName: sheetTitle + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                sheetName: sheetTitle,
                hiddenVisible: false,
            };
            $c.data.downloadGridViewExcel(grdObj, options, infoArr);
        }

    } else {
        $c.win.alert(MSG_CM_WRN_002);
    }
}


