                        s_ed_userId.setValue("");
                        s_txt_userNm.setValue("");
                    }
                }
                , pCode// 화면에서의 ??? Code Element의Value
                , pName// 화면에서의 ??? Name Element의Value
                , pClose // 결과가 1건 일때원도우를AutoClose 여부(T:Close,F:Opened)
                , null // 검색 결과컬럼의 보여주는개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는컬럼 지정 
                , null // SQL절의 WHERE절에원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의폭
                , null // POP-UP뛰을때 우도우의 사용자 정의높이
                , null // 윈도우 위치 Y좌표 
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 2:  //부서조회  //retrieveLogisDeptInfo
            await udc_deptPopup.cfCommonPopUpAsync(
                async (rtnList) => {
                    if (rtnList != null && rtnList[0] != "N/A") {
                        s_ed_acctDeptCd.setValue(rtnList[0]);
                        s_txt_acctDeptNm.setValue(rtnList[1]);
                    } else {
                        s_ed_acctDeptCd.setValue("");
                        s_txt_acctDeptNm.setValue("");
                    }
                }
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch             // 전체검색허용여부 ("F")
                , null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 3:
            // 사용자 팝업 (조회 팝업)
            await udc_userPopup2.cfCommonPopUpAsync(
                async (rtnList) => {
                    if (rtnList != null && rtnList[0] != "N/A") {
                        ed_userId.setValue(rtnList[0]); // userId
                        txt_userNm.setValue(rtnList[1]); // userNm
                    } else {
                        ed_userId.setValue("");
                        txt_userNm.setValue("");
                    }
                }
                , pCode// 화면에서의 ??? Code Element의Value
                , pName// 화면에서의 ??? Name Element의Value
                , pClose // 결과가 1건 일때원도우를AutoClose 여부(T:Close,F:Opened)
                , null // 검색 결과컬럼의 보여주는개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는컬럼 지정 
                , null // SQL절의 WHERE절에원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의폭
                , null // POP-UP뛰을때 우도우의 사용자 정의높이
                , null // 윈도우 위치 Y좌표 
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , null // POP-UP Window Title 검색어1,2("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 4:  //부서조회  //retrieveLogisDeptInfo
            rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo' // XML상의 SELECT ID  
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서  
                , null                   // 보여주는 각 컬럼들의 폭    
                , null                   // 컬럼중에서 숨기는    컬럼 지정   
                , null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                , null                   // 윈도우 위치 Y좌표   
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch             // 전체검색허용여부 ("F")
                , null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            //cfSetReturnValue(rtnList, txt_deptCd, txt_deptNm);
            if (rtnList != null && rtnList[0] != "N/A") {
                ed_acctDeptCd.setValue(rtnList[0]);
                txt_acctDeptNm.setValue(rtnList[1]);
            } else {
                ed_acctDeptCd.setValue("");
                txt_acctDeptNm.setValue("");
            }
            break;

        default:
            break;
    }
}


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------  
scwin.f_Create = function () {
    $c.gus.cfDisableBtn([b_Create, b_Update, b_Apprv, b_CancelApprv]);
    $c.gus.cfEnableBtnOnly([b_Cancel, b_Save, btn_userId, btn_fileNm]);
    $c.gus.cfEnableObjects([ed_userId, txt_userNm, txt_vehclNo, txt_vehclNm, lc_fuelKndCd, txt_carVolume, txt_flEffcncy]);
    ds_vehclInfo.insertRow();  // 행추가
    ds_vehclInfo.setCellData(ds_vehclInfo.getTotalRow() - 1, "useYn", "1");
    ds_vehclInfo.setCellData(ds_vehclInfo.getTotalRow() - 1, "apprvYn", "0");
    gr_vehclInfo.setFocusedCell(ds_vehclInfo.getTotalRow() - 1, "userNm", false);
}


//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------  
scwin.f_Update = function () {
    $c.gus.cfEnableObjects([ed_userId, txt_userNm, txt_vehclNm, lc_fuelKndCd
        , txt_carVolume, txt_flEffcncy, lc_useYn]);

    $c.gus.cfEnableBtnOnly([b_Cancel, b_Save, btn_userId, btn_fileNm]);
    $c.gus.cfDisableBtn([b_Create, b_Update, b_Apprv, b_CancelApprv]);
}


// to-do
//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    $c.data.undoRow(ds_vehclInfo);

    if (ds_vehclInfo.getTotalRow() > 0) {
        if (ds_vehclInfo.getCellData(ds_vehclInfo.getRowPosition(), "apprvYn") == "1") {
            $c.gus.cfEnableBtnOnly([b_Create, b_Update, b_CancelApprv]);
            $c.gus.cfDisableBtn([b_Apprv, b_Save, b_Cancel]);
        } else {
            $c.gus.cfEnableBtnOnly([b_Create, b_Update, b_Apprv]);
            $c.gus.cfDisableBtn([b_Save, b_Cancel, b_CancelApprv]);
        }
    } else {
        $c.gus.cfDisableAllBtn();
        // b_Cancel.setDisabled(true);
        // b_Save.setDisabled(true);
    }
    $c.gus.cfEnableBtnOnly([btn_retrieve]);
    $c.gus.cfDisableObjects(
        [ed_userId, txt_userNm, txt_vehclNo
            , txt_vehclNm, lc_fuelKndCd, txt_carVolume
            , lc_apprvYn, lc_useYn, txt_flEffcncy]
    );
}


//-------------------------------------------------------------------------
// function desc : 파일 첨부하기
//-------------------------------------------------------------------------    
scwin.f_fileSet = async function () {

    var argObject = new Object();
    var row = ds_vehclInfo.getRowPosition();

    argObject.attachFileNm = txt_fileNm.getValue();
    argObject.attachFilePath = txt_filePath.getValue();
    argObject.attachFilePath = txt_fileSiz.getValue();

    let argPath = "";
    // var dialSize = "";
    // /ui/ps/rc/fms/imgnt/rc_606_01_04b

    argPath = "/ui/ps/rc/fms/imgnt/rc_606_01_04p.xml"; // 화면 없음.
    // dialSize = "dialogWidth:650px; dialogHeight:250px; status:no; scroll:yes";

    let opts = {
        id: "pupup",
        popupName: "",
        modal: true,
        type: "browserPopup",
        width: 650,
        height: 250,
        title: ""
    };

    let resultList = await $c.win.openPopup(argPath, opts); // arrParent

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            txt_filePath.setValue(resultList[0]);
            txt_fileNm.setValue(resultList[1]);
            txt_fileSiz.setValue(resultList[2]);
        }
    }
}

//-------------------------------------------------------------------------
// function name : f_Download
//-------------------------------------------------------------------------
scwin.f_Download = function () {
    var row = ds_vehclInfo.getRowPosition();

    if (row < 0) {
        return;
    } else {
        var fileName = ds_vehclInfo.getCellData(row, "fileNm");
        var filePath = ds_vehclInfo.getCellData(row, "filePath");
        if (filePath.trim().length == 0) {
            $c.win.alert("선택하신 " + (row + 1) + "행에 파일이 등록되어 있지 않습니다.");
        } else {
            $c.gus.cfDownloadFile(fileName, filePath);
        }
    }
}

scwin.sbm_retrieve_submit = function (e) {
    ds_Retrieve.set("acctDeptCd", s_ed_acctDeptCd.getValue())
    ds_Retrieve.set("userId", s_ed_userId.getValue());
};

// for=tr_retrieve event=OnSuccess()
scwin.sbm_retrieve_submitdone = function (e) {

    let rowCnt = ds_vehclInfo.getTotalRow();

    if (rowCnt == 0) {
        totalRows.setValue(rowCnt)
        $c.win.alert(MSG_CM_ERR_003);
    } else {
        totalRows.setValue(rowCnt)
    }

    // 조회후 첫번째 행에 focus
    gr_vehclInfo.setFocusedCell(0, "userNm", false);

    if (ds_vehclInfo.getTotalRow() > 0) {
        if (ds_vehclInfo.getCellData(ds_vehclInfo.getRowPosition(), "apprvYn") == "0") {
            $c.gus.cfEnableBtnOnly([b_Create, b_Update, b_Apprv]);
            $c.gus.cfDisableBtn([b_Save, b_Cancel, btn_fileNm, b_CancelApprv, btn_userId]);
        } else {
            $c.gus.cfEnableBtnOnly([b_Create, b_CancelApprv]);
            $c.gus.cfDisableBtn([b_Save, b_Update, b_Cancel, btn_fileNm, b_Apprv, btn_userId]);
        }
    } else {
        $c.gus.cfDisableBtn([b_Save, b_Cancel, b_Update, b_Apprv, b_CancelApprv, btn_fileNm, btn_userId]);
    }

    $c.gus.cfDisableObjects(
        [ed_userId, txt_userNm, txt_vehclNo, txt_vehclNm, lc_fuelKndCd,
            txt_carVolume, lc_apprvYn, lc_useYn, txt_flEffcncy
        ]);
};

// for= tr_save event = OnSuccess()
scwin.sbm_save_submitdone = async function (e) {
    await scwin.f_Retrieve();
};

// for=tr_apprvYn event=OnSuccess()
scwin.sbm_apprvYn_submitdone = async function (e) {
    await scwin.f_Retrieve();
};

// for=gr_vehclInfo event=OnClick(row,colid)
scwin.gr_vehclInfo_oncellclick = function (rowIndex, columnIndex, columnId) {
    var row_Statuse = ds_vehclInfo.getRowStatusValue(rowIndex);

    // 0:Normal,3:Update,1:Insert,4:Logical,2:Delete 
    // (초기상태:0, 갱신:1, 삽입:2, 삭제:3, 삽입 후 삭제:4) to-be
    if (row_Statuse == "0") { // 0 -> 1
        if (ds_vehclInfo.getCellData(rowIndex, "apprvYn") == 1) {
            $c.gus.cfDisableObjects(
                [ed_userId, txt_userNm, txt_vehclNo,
                    txt_vehclNm, lc_fuelKndCd, txt_carVolume,
                    lc_apprvYn, lc_useYn, txt_flEffcncy]);
            $c.gus.cfDisableBtn([b_Save, b_Cancel, b_Update, b_Apprv, btn_fileNm, btn_userId]);
            $c.gus.cfEnableBtnOnly([b_Create, b_CancelApprv]);
        } else {
            $c.gus.cfDisableObjects(
                [ed_userId, txt_userNm, txt_vehclNo, txt_vehclNm,
                    lc_fuelKndCd, txt_carVolume, lc_apprvYn, lc_useYn, txt_flEffcncy]);
            $c.gus.cfDisableBtn(
                [b_Save, b_Cancel, b_Update, b_CancelApprv, btn_fileNm, btn_userId]);
            $c.gus.cfEnableBtnOnly([b_Create, b_Update, b_Apprv]);
        }
    } else if (row_Statuse == "2") { //신규일때 1 -> 2
        $c.gus.cfEnableObjects(
            [ed_userId, txt_userNm, txt_vehclNo, txt_vehclNm,
                lc_fuelKndCd, txt_carVolume, lc_apprvYn, txt_flEffcncy]);
        $c.gus.cfDisableBtn([b_Update, b_Apprv, b_CancelApprv]);

        // b_Create 추가함 
        $c.gus.cfEnableBtnOnly([b_Create, b_Save, b_Cancel, btn_userId, btn_fileNm]);
    } else if (row_Statuse == "3") { //삭제일때 2 -> 3
        $c.gus.cfEnableBtnOnly([b_Save, b_Cancel]);
        $c.gus.cfDisableBtn([b_Create, b_Update, b_Apprv, b_CancelApprv]);
        $c.gus.cfDisableObjects(
            [ed_userId, txt_userNm, txt_vehclNo
                , txt_vehclNm, lc_fuelKndCd, txt_carVolume
                , lc_apprvYn, lc_useYn, txt_flEffcncy]
        );
    } else if (row_Statuse == "3") {  //수정일때 3 ->4
        $c.gus.cfEnableObjects(
            [ed_userId, txt_userNm, txt_vehclNm, lc_fuelKndCd,
                txt_carVolume, lc_apprvYn, txt_flEffcncy]);
        $c.gus.cfDisableBtn([b_Update, b_Apprv, b_CancelApprv]);
        $c.gus.cfEnableBtnOnly([b_Save, b_Cancel, btn_userId, btn_fileNm]);
    }
};
